function initPage() { const existingMenuToggle = document.querySelector('.menu-toggle'); if (!existingMenuToggle) { const navMenu = document.querySelector('.nav-menu'); const navbarContainer = document.querySelector('.navbar .container'); if (navMenu && navbarContainer) { const menuToggle = document.createElement('div'); menuToggle.classList.add('menu-toggle'); menuToggle.innerHTML = '<i class="fas fa-bars"></i>'; navbarContainer.prepend(menuToggle); let backdrop = document.querySelector('.nav-backdrop'); if (!backdrop) { backdrop = document.createElement('div'); backdrop.classList.add('nav-backdrop'); document.body.appendChild(backdrop); } function toggleMenu() { navMenu.classList.toggle('active'); backdrop.classList.toggle('active'); menuToggle.innerHTML = navMenu.classList.contains('active') ? '<i class="fas fa-times"></i>' : '<i class="fas fa-bars"></i>'; document.body.style.overflow = navMenu.classList.contains('active') ? 'hidden' : ''; } menuToggle.onclick = toggleMenu; backdrop.onclick = toggleMenu; navMenu.querySelectorAll('a').forEach(link => { link.onclick = () => { if (navMenu.classList.contains('active')) { toggleMenu(); } }; }); } } const slides = document.querySelectorAll('.slide'); if (slides.length > 0) { let currentSlide = 0; if (window.sliderInterval) clearInterval(window.sliderInterval); function showSlide(index) { slides.forEach(slide => slide.classList.remove('active')); slides[index].classList.add('active'); } function nextSlide() { currentSlide = (currentSlide + 1) % slides.length; showSlide(currentSlide); } window.sliderInterval = setInterval(nextSlide, 5000); } document.querySelectorAll('a[href^="#"]').forEach(anchor => { anchor.onclick = function (e) { const targetId = this.getAttribute('href'); if (targetId === '#') return; const target = document.querySelector(targetId); if (target) { e.preventDefault(); target.scrollIntoView({ behavior: 'smooth', block: 'start' }); } }; }); let scrollBtn = document.querySelector('.scroll-top'); if (!scrollBtn) { scrollBtn = document.createElement('button'); scrollBtn.innerHTML = '<i class="fas fa-arrow-up"></i>'; scrollBtn.classList.add('scroll-top'); document.body.appendChild(scrollBtn); } scrollBtn.onclick = () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }; const videoSection = document.querySelector('.video-showcase'); const video = document.getElementById('promo-video'); const overlay = document.getElementById('video-overlay'); if (videoSection && video && overlay) { const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting && !window.videoPlayed) { playPromoVideo(); observer.unobserve(entry.target); } }); }, { threshold: 0.5 }); observer.observe(videoSection); } const currentPath = window.location.pathname.split('/').pop() || 'index.html'; document.querySelectorAll('.nav-menu a').forEach(a => { const href = a.getAttribute('href'); if (href === currentPath) { a.classList.add('active'); } else { a.classList.remove('active'); } }); } function showTab(tabName) { const tabs = document.getElementsByClassName('tab-content'); const buttons = document.getElementsByClassName('tab-btn'); for (let i = 0; i < tabs.length; i++) tabs[i].classList.remove('active'); for (let i = 0; i < buttons.length; i++) buttons[i].classList.remove('active'); const target = document.getElementById(tabName); if (target) target.classList.add('active'); if (window.event && window.event.currentTarget) { window.event.currentTarget.classList.add('active'); } } function filterGallery(category) { const items = document.getElementsByClassName('gallery-item'); const buttons = document.getElementsByClassName('filter-btn'); for (let i = 0; i < buttons.length; i++) buttons[i].classList.remove('active'); if (window.event && window.event.currentTarget) { window.event.currentTarget.classList.add('active'); } for (let i = 0; i < items.length; i++) { items[i].style.display = (category === 'all' || items[i].getAttribute('data-category') === category) ? 'block' : 'none'; } } function openLightbox(imgSrc, caption) { const lightbox = document.getElementById('lightbox'); const lightboxImg = document.getElementById('lightboxImg'); const lightboxCaption = document.getElementById('lightboxCaption'); if (lightbox && lightboxImg && lightboxCaption) { lightboxImg.src = imgSrc; lightboxCaption.textContent = caption; lightbox.classList.add('active'); } } function closeLightbox() { const lightbox = document.getElementById('lightbox'); if (lightbox) lightbox.classList.remove('active'); } function submitForm(event) { event.preventDefault(); const name = document.getElementById('name')?.value; const email = document.getElementById('email')?.value; const phone = document.getElementById('phone')?.value; const message = document.getElementById('message')?.value; if (!name || !email || !phone || !message) { alert('Please fill in all required fields'); return false; } alert('Thank you for contacting us! We will get back to you soon.'); if (event.target) event.target.reset(); return false; } function submitEnquiry(event) { event.preventDefault(); alert('Thank you for your enquiry! Our admission team will contact you soon.'); if (event.target) event.target.reset(); return false; } function playPromoVideo() { const overlay = document.getElementById('video-overlay'); const video = document.getElementById('promo-video'); if (overlay && video) { overlay.style.opacity = '0'; overlay.style.pointerEvents = 'none'; setTimeout(() => { overlay.style.display = 'none'; }, 500); video.play().catch(console.error); window.videoPlayed = true; } } let isScrolling = false; window.onscroll = () => { if (!isScrolling) { window.requestAnimationFrame(() => { const scrollBtn = document.querySelector('.scroll-top'); if (scrollBtn) scrollBtn.style.display = window.pageYOffset > 300 ? 'flex' : 'none'; const siteHeader = document.getElementById('site-header'); const titleObj = document.getElementById('school-title'); const addressObj = document.getElementById('school-address'); if (siteHeader && titleObj && addressObj) { if (window.scrollY > 50) { if (!siteHeader.classList.contains('scrolled')) { siteHeader.classList.add('scrolled'); titleObj.style.opacity = '0'; addressObj.style.opacity = '0'; setTimeout(() => { titleObj.textContent = 'SPIC'; addressObj.textContent = 'Prayagraj'; requestAnimationFrame(() => { titleObj.style.opacity = '1'; addressObj.style.opacity = '1'; }); }, 300); } } else if (siteHeader.classList.contains('scrolled')) { siteHeader.classList.remove('scrolled'); titleObj.style.opacity = '0'; addressObj.style.opacity = '0'; setTimeout(() => { titleObj.textContent = 'SARDAR PATEL INTER COLLEGE'; addressObj.textContent = 'Sikaron Koraon, Prayagraj 212306'; requestAnimationFrame(() => { titleObj.style.opacity = '1'; addressObj.style.opacity = '1'; }); }, 300); } } isScrolling = false; }); isScrolling = true; } }; document.addEventListener('DOMContentLoaded', initPage);